const body = items[0].json;
const allowedErrorTypes = ["http_error", "timeout", "validation_error", "unsupported_event_type", "module_unavailable", "schema_mismatch", "unknown_error"];

let error_type = body.error_type || "unknown_error";
let normalized_notes = "";

if (!allowedErrorTypes.includes(error_type)) {
  error_type = "unknown_error";
  normalized_notes = "Unsupported error_type normalized to unknown_error.";
}

// 1. Determine retryable flag dynamically if not provided
let retryable = true;
if (["validation_error", "unsupported_event_type", "schema_mismatch", "unknown_error"].includes(error_type)) {
  retryable = false;
}

// 2. Decide next action and retry_decision
let retry_decision = "no_retry";
let next_action = "stop";

if (error_type === "unsupported_event_type" || normalized_notes !== "") {
  retry_decision = "manual_review_required";
  next_action = "manual_review_required";
} else if (retryable) {
  if (body.attempt < body.max_attempts) {
    retry_decision = "retry_scheduled";
    next_action = "retry";
  } else {
    retry_decision = "exhausted_to_dead_letter";
    next_action = "dead_letter";
  }
} else {
  retry_decision = "no_retry";
  next_action = "stop";
}

